using UnityEngine;

/// <summary>
/// Puxar um PushableBlock (correcção ao P6 — "empurrar" é só encostar; "puxar"
/// é uma capacidade extra de alguns animais: AnimalFormData.canPull).
///
/// Uso: SEGURAR Interagir junto a um PushableBlock que a forma consiga mover
/// (mesma verificação de força do empurrão — PushStrength) e ANDAR PARA TRÁS
/// (input horizontal oposto ao "facing"): o bloco é arrastado a favor do
/// movimento do player, mas mais lento ("com dificuldade") — o player também
/// fica mais lento enquanto puxa (ver playerSlowMultiplier).
///
/// Não interfere com agarrar objectos (GrabThrowAbility) nem com escalar
/// (ClimbAbility) — Interagir não pode estar a ser usado por essas acções ao
/// mesmo tempo.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class PullAbility : MonoBehaviour, IFormAbility
{
    [Header("Puxar (canPull)")]
    [Tooltip("Alcance à frente do player para detectar um PushableBlock.")]
    public float pullRange = 1f;

    [Tooltip("Multiplicador de velocidade do PLAYER enquanto puxa (mais lento — 'com dificuldade').")]
    [Range(0.05f, 1f)] public float playerSlowMultiplier = 0.5f;

    [Tooltip("Quanto de input horizontal (oposto ao facing) é preciso para considerar 'andar para trás'.")]
    [Range(0f, 1f)] public float backwardInputThreshold = 0.2f;

    [Header("Input")]
    [Tooltip("Auto-preenchido.")]
    [SerializeField] private PlayerInputRouter input;
    [SerializeField] private GrabThrowAbility grabThrow;
    [SerializeField] private ClimbAbility climb;
    [SerializeField] private SwingAbility swing;

    private PlayerMotor2D motor;
    private WaterDetector waterDetector;

    private AnimalFormData form;
    private bool canPull;
    private bool isPulling;

    /// <summary>true enquanto o player está activamente a arrastar um bloco.</summary>
    public bool IsPulling => isPulling;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        waterDetector = GetComponent<WaterDetector>();

        if (input == null) input = GetComponent<PlayerInputRouter>();
        if (grabThrow == null) grabThrow = GetComponent<GrabThrowAbility>();
        if (climb == null) climb = GetComponent<ClimbAbility>();
        if (swing == null) swing = GetComponent<SwingAbility>();
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        canPull = form != null && form.canPull;
        StopPull();
    }

    private void Update()
    {
        if (!canPull || input == null || !input.InteractHeld)
        {
            StopPull();
            return;
        }

        // Interagir já está ocupado a agarrar/escalar/balançar — não puxa ao mesmo tempo.
        if ((grabThrow != null && grabThrow.IsCarrying) || (climb != null && climb.IsClimbing) ||
            (swing != null && swing.IsSwinging))
        {
            StopPull();
            return;
        }

        int facing = motor.FacingSign != 0 ? motor.FacingSign : 1;
        float moveX = input.Move.x;

        bool movingBackward = Mathf.Abs(moveX) >= backwardInputThreshold && Mathf.Sign(moveX) != Mathf.Sign(facing);

        var block = movingBackward ? FindBlockInFront(facing) : null;
        bool inWater = waterDetector != null && waterDetector.IsInWater;

        if (block == null || !block.CanBeMoved(form, inWater))
        {
            StopPull();
            return;
        }

        isPulling = true;
        motor.SetSpeedMultiplier(playerSlowMultiplier);
        block.Pull(motor.RB.linearVelocity);
    }

    private void StopPull()
    {
        if (!isPulling) return;

        isPulling = false;
        motor.SetSpeedMultiplier(1f);
    }

    /// <summary>Procura um PushableBlock à frente do player (lado para onde está virado).</summary>
    private PushableBlock FindBlockInFront(int facing)
    {
        Vector2 center = (Vector2)transform.position + new Vector2(facing * pullRange * 0.5f, 0f);
        var hits = Physics2D.OverlapBoxAll(center, new Vector2(pullRange, 1f), 0f);

        foreach (var hit in hits)
        {
            if (hit == null || hit.gameObject == gameObject) continue;

            var block = hit.GetComponent<PushableBlock>();
            if (block != null) return block;
        }

        return null;
    }

    private void OnDisable() => StopPull();

    private void OnDrawGizmosSelected()
    {
        int facing = motor != null && motor.FacingSign != 0 ? motor.FacingSign : 1;
        Vector2 center = (Vector2)transform.position + new Vector2(facing * pullRange * 0.5f, 0f);

        Gizmos.color = new Color(1f, 0.6f, 0.1f, 0.5f);
        Gizmos.DrawWireCube(center, new Vector2(pullRange, 1f));
    }
}
